  "lender_type": "bank / insurance / fund",
  "lender_definition_clause": "אחד מחמשת הבנקים הגדולים בישראל ו/או אחת מארבע חברות ביטוח הגדולות בישראל ו/או בשילוב קרן \"יסודות\" ו/או קרן \"מכלול\" ו/או קרן \"ארכימדס\" ו/או קרן \"ברקת\" ו/או קרן \"פנינסולה מבית מיטב\" ו/או כל קרן אחרת בעלת ניסיון בליווי פיננסי לפרויקטים מסוג זה, בכפוף לאישור הנציגות), עמו יתקשר היזם בהסכם לצורך קבלת מימון לביצוע הפרויקט במתכונת של ליווי סגור, ולצורך מתן ערבויות בנקאיות ו/או פוליסות ביטוח לבעלים על פי הסכם זה ולרוכשי דירות היזם.",
  "lender_allows_funds": true,
  "guarantees": [
    {
      "guarantee_type": "ערבות חוק המכר",
      "amount": "שווי ערכה המלא של דירתו החדשה של יחיד הבעלים בהתאמה, כולל רכיב המע\"מ, בסכום כפי שיקבע על ידי השמאי",
      "trigger_condition": "כנגד רישום שעבוד מלוא הזכויות במקרקעין ורישום משכנתא ראשונה בדרגה ללא הגבלה בסכום בפועל על כל זכויות הבעלים במקרקעין לטובת הבנק המלווה",
      "source": {
        "source_document_name": "הסכם פרויקט דה האז 16 חתום סופי-1-68.pdf",
        "page_number": 45,
        "verbatim_quote": "כנגד רישום שעבוד מלוא הזכויות במקרקעין ורישום משכנתא ראשונה בדרגה ללא הגבלה בסכום בפועל על כל זכויות הבעלים במקרקעין לטובת הבנק המלווה בהתאם להוראות הסכם זה ובכפוף לפינוי כל הדירות הנוכחיות בהתאם להוראות ההסכם, היזם מתחייב להמציא לכל אחד מיחידי הבעלים ערבות בנקאית צמודה למדד תשומות הבנייה למגורים, בנוסח שלפי הוראות חוק המכר (דירות) (הבטחת השקעות של רוכשי דירות), התשל\"ה 1974 (להלן: \"חוק המכר הבטחת השקעות\"), בשווי ערכה המלא של דירתו החדשה של יחיד הבעלים בהתאמה, כולל רכיב המע\"מ, בסכום כפי שיקבע על ידי השמאי כהגדרתו בסעיף 2 לעיל"
      }
    },
    {
      "guarantee_type": "ערבות שכירות",
      "amount": "בסך של דמי השכירות המוסכמים עבור אותו יחיד בעלים לתקופה של 30 חודשים",
      "trigger_condition": "לפני מועד הפינוי כהגדרתו וכתנאי לפינוי הדירות הנוכחיות",
      "source": {
        "source_document_name": "הסכם פרויקט דה האז 16 חתום סופי-1-68.pdf",
        "page_number": 45,
        "verbatim_quote": "להבטחת תשלום דמי השכירות המוסכמים בהתאם להוראות סעיף 8.1 לעיל, יפקיד היזם בידי ב\"כ הבעלים בנאמנות לפני מועד הפינוי כהגדרתו וכתנאי לפינוי הדירות הנוכחיות עבור כל יחיד בעלים שפינה את דירתו בפועל בהתאם להוראות סעיף 9.2 לעיל בנפרד או עבור כלל הבעלים (שפינו את דירותיהם) יחד, עפ\"י החלטת החברה, ערבות בנקאית אוטונומית פוחתת, צמודה למדד המחירים לצרכן, בסך של דמי השכירות המוסכמים עבור אותו יחיד בעלים לתקופה של 30 חודשים(לעיל ולהלן: \"ערבות השכירות\")."
      }
    },
    {
      "guarantee_type": "ערבות מס שבח",
      "amount": "בגובה מס השבח הצפוי לחול על הבעלים עפ\"י חוות הדעת",
      "trigger_condition": "עד למועד הפינוי בפועל",
      "source": {
        "source_document_name": "הסכם פרויקט דה האז 16 חתום סופי-1-68.pdf",
        "page_number": 46,
        "verbatim_quote": "בכפוף להוראות סעיף 9.2 לעיל, עד למועד הפינוי בפועל כהגדרתו בסעיף 9.1 לעיל, יציג היזם חוות דעת של יועץ מיסוי מטעמו לב\"כ הבעלים בו יצוין גובה מס השבח הצפוי לחול על הבעלים, בהתאם להוראות (להלן: \"חוות הדעת\") או אישור בדבר פטור מתשלום מס השבח כאמור, היזם יפקיד בידי ב\"כ הבעלים עד למועד הפינוי בפועל ערבות בנקאית אוטונומית צמודה למדד המחירים לצרכן בגובה מס השבח הצפוי לחול על הבעלים עפ\"י חוות הדעת, לפקודת רשויות מיסוי מקרקעין"
      }
    },
    {
      "guarantee_type": "ערבות בדק",
      "amount": "בשיעור של 3% (שלושה אחוז) משווי עלות ביצוע העבודות לבעלים, כפי שייקבע על ידי השמאי",
      "trigger_condition": "במועד מסירת כל אחת מדירות הבעלים",
      "source": {
        "source_document_name": "הסכם פרויקט דה האז 16 חתום סופי-1-68.pdf",
        "page_number": 46,
        "verbatim_quote": "ערבות בנקאית אוטונומית בשיעור של 3% (שלושה אחוז) משווי עלות ביצוע העבודות לבעלים, כפי שייקבע על ידי השמאי כהגדרתו בסעיף 2 לעיל, אשר תהיה בנוסח המצ\"ב כנספח טו' להסכם זה, שתימסר לב\"כ הבעלים במועד מסירת כל אחת מדירות הבעלים ותהיה בתוקף ביחס לכל דירה, ממועד מסירתה בפועל בהתאם להוראות ההסכם ועד לתום 18 חודשים ממועד זה"
      }
    },
    {
      "guarantee_type": "ערבות רישום",
      "amount": "60,000 ₪",
      "trigger_condition": "בתום תקופת הבדק, היה ולא נרשם הבית המשותף",
      "source": {
        "source_document_name": "הסכם פרויקט דה האז 16 חתום סופי-1-68.pdf",
        "page_number": 46,
        "verbatim_quote": "בתום תקופת הבדק, היה ולא נרשם הבית המשותף, תופחת ערבות הבדק ותעמוד על סך של 60,000 ₪ (שישים אלף שקלים חדשים) ותהיה בתוקף ממועד זה ועד לתום 24 חודשים ממועד זה, וזאת לצורך הבטחת רישום הבית המשותף וייחוד דירות הבעלים על שמם."
      }
    }
  ],
  "alternative_financing": "ההסכם מתיר במפורש שימוש בקרנות מימון, בכפוף לאישור הנציגות.",
  "alternative_financing_conditions": "הגדרת \"הבנק המלווה\" כוללת במפורש את קרן \"יסודות\", קרן \"מכלול\", קרן \"ארכימדס\", קרן \"ברקת\", וקרן \"פנינסולה מבית מיטב\". כמו כן, ההגדרה כוללת \"כל קרן אחרת בעלת ניסיון בליווי פיננסי לפרויקטים מסוג זה, בכפוף לאישור הנציגות\".",
